B.LP=s(["\u03a4\u03bf \u03b4\u03af\u03ba\u03c4\u03b1\u03bc\u03bf (Origanum dictamnus), \u03b3\u03bd\u03c9\u03c3\u03c4\u03cc \u03ba\u03b1\u03b9 \u03c9\u03c2 <<\u03b4\u03af\u03ba\u03c4\u03b1\u03bc\u03bf \u03c4\u03b7\u03c2 \u039a\u03c1\u03ae\u03c4\u03b7\u03c2>> , \u03b5\u03af\u03bd\u03b1\u03b9 \u03ad\u03bd\u03b1\u03c2 \u03bc\u03b9\u03ba\u03c1\u03cc\u03c2 \u03b1\u03c1\u03c9\u03bc\u03b1\u03c4\u03b9\u03ba\u03cc\u03c2 \u03b8\u03ac\u03bc\u03bd\u03bf\u03c2 \u03bc\u03b5 \u03c3\u03c4\u03c1\u03bf\u03b3\u03b3\u03c5\u03bb\u03ac \u03c6\u03cd\u03bb\u03bb\u03b1 \u03ba\u03b1\u03b9 \u03cc\u03bc\u03bf\u03c1\u03c6\u03b1 \u03ba\u03b1\u03b9 \u03cc\u03bc\u03bf\u03c1\u03c6\u03b1 \u03c1\u03bf\u03b6/\u03bc\u03c9\u03b2 \u03ac\u03bd\u03b8\u03b7 \u03c4\u03bf \u03ba\u03b1\u03bb\u03bf\u03ba\u03b1\u03af\u03c1\u03b9. \u0391\u03b3\u03b1\u03c0\u03ac \u03c4\u03b9\u03c2 \u03b7\u03bb\u03b9\u03cc\u03bb\u03bf\u03c5\u03c3\u03c4\u03b5\u03c2 \u03c4\u03bf\u03c0\u03bf\u03b8\u03b5\u03c3\u03af\u03b5\u03c2 \u03ba\u03b1\u03b9 \u03c7\u03c1\u03b5\u03b9\u03ac\u03b6\u03b5\u03c4\u03b1\u03b9 \u03bb\u03af\u03b3\u03bf \u03c0\u03cc\u03c4\u03b9\u03c3\u03bc\u03b1. \u0391\u03bd\u03c4\u03ad\u03c7\u03b5\u03b9 \u03c4\u03b9\u03c2 \u03c7\u03b1\u03bc\u03b7\u03bb\u03ad\u03c2 \u03b8\u03b5\u03c1\u03bc\u03bf\u03ba\u03c1\u03b1\u03c3\u03af\u03b5\u03c2 \u03c4\u03bf\u03c5 \u03c7\u03b5\u03b9\u03bc\u03ce\u03bd\u03b1, \u03b3\u03b5\u03b3\u03bf\u03bd\u03cc\u03c2 \u03c0\u03bf\u03c5 \u03c4\u03bf \u03ba\u03b1\u03b8\u03b9\u03c3\u03c4\u03ac \u03b9\u03b4\u03b1\u03bd\u03b9\u03ba\u03cc, \u03c4\u03cc\u03c3\u03bf \u03b3\u03b9\u03b1 \u03c4\u03b7\u03bd \u03ba\u03b1\u03bb\u03bb\u03b9\u03ad\u03c1\u03b3\u03b5\u03b9\u03b1 \u03c3\u03c4\u03bf\u03bd \u03b1\u03b3\u03c1\u03cc, \u03cc\u03c3\u03bf \u03ba\u03b1\u03b9 \u03b3\u03b9\u03b1 \u03c7\u03c1\u03ae\u03c3\u03b7 \u03c3\u03c4\u03bf \u03bc\u03c0\u03b1\u03bb\u03ba\u03cc\u03bd\u03b9. \u039c\u03c0\u03bf\u03c1\u03b5\u03af \u03bd\u03b1 \u03c7\u03c1\u03b7\u03c3\u03b9\u03bc\u03bf\u03c0\u03bf\u03b9\u03b7\u03b8\u03b5\u03af \u03c3\u03c4\u03bf \u03c6\u03b1\u03b3\u03b7\u03c4\u03cc, \u03c3\u03b5 \u03c3\u03b1\u03bb\u03ac\u03c4\u03b5\u03c2 \u03ba\u03b1\u03b9 \u03c8\u03b7\u03c4\u03ac \u03b1\u03bd\u03c4\u03af \u03b3\u03b9\u03b1 \u03c1\u03af\u03b3\u03b1\u03bd\u03b7 (\u03ba\u03b1\u03b9 \u03c4\u03b1 \u03ac\u03bd\u03b8\u03b7 \u03ba\u03b1\u03b9 \u03c4\u03b1 \u03c6\u03c5\u03c4\u03ac). \u03a3\u03c5\u03bd\u03b9\u03c3\u03c4\u03ac, \u03b5\u03c0\u03af\u03c3\u03b7\u03c2, \u03c9\u03c2 \u03b1\u03c6\u03ad\u03c8\u03b7\u03bc\u03b1 \u03b3\u03b9\u03b1 \u03c4\u03b9\u03c2 \u03ba\u03b1\u03c4\u03b1\u03c0\u03c1\u03b1\u03cb\u03bd\u03c4\u03b9\u03ba\u03ad\u03c2 \u03c4\u03bf\u03c5 \u03b9\u03b4\u03b9\u03cc\u03c4\u03b7\u03c4\u03b5\u03c2. "],t.s)
